const topics = $.input.topics || 'AI, programming, startups, tech industry';
const query = 'site:news.ycombinator.com trending discussions about ' + topics;
return { query };

const results = $.steps.searchHN.response.results || [];
let compiled = '';
const items = [];
results.forEach((r, i) => {
  compiled += 'THREAD ' + (i + 1) + ':\n';
  compiled += 'Title: ' + (r.title || 'Untitled') + '\n';
  compiled += 'URL: ' + (r.url || '') + '\n';
  compiled += 'Content: ' + (r.text || '').slice(0, 1500) + '\n\n';
  items.push({ index: i + 1, title: r.title || 'Untitled', url: r.url || '' });
});
return { compiled, items, count: results.length };

const d = $.steps.compileResults.output;
const topics = $.input.topics || 'AI, programming, startups, tech industry';

let prompt = 'You are a tech industry analyst specializing in HackerNews trends. Analyze the following HackerNews discussions and create structured insights.\n\n';
prompt += 'TOPICS OF INTEREST: ' + topics + '\n';
prompt += 'THREADS FOUND: ' + d.count + '\n\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Summarize each thread into a concise, human-readable insight\n';
prompt += '- Identify overarching trends across threads\n';
prompt += '- Rate each thread by relevance and engagement potential (1-10)\n';
prompt += '- Group related threads by theme\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "threads": [\n';
prompt += '    { "title": "thread title", "url": "url", "summary": "2-3 sentence insight", "theme": "category", "relevanceScore": 8, "keyTakeaway": "one-line takeaway" }\n';
prompt += '  ],\n';
prompt += '  "trendingSummary": "2-3 sentence overview of what the HN community is discussing",\n';
prompt += '  "topThemes": [{ "theme": "name", "threadCount": 2, "description": "brief" }],\n';
prompt += '  "actionableInsights": ["insight 1", "insight 2"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { threads: [], trendingSummary: raw, topThemes: [], actionableInsights: [] }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Title', 'URL', 'Theme', 'Summary', 'Key Takeaway', 'Relevance Score']);
(ai.threads || []).forEach(t => {
  rows.push([today, t.title || '', t.url || '', t.theme || '', t.summary || '', t.keyTakeaway || '', String(t.relevanceScore || '')]);
});
return { rows };

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'HackerNews Trend Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Trending Summary:* ' + (ai.trendingSummary || 'No summary available').slice(0, 1800) } });
blocks.push({ type: 'divider' });

if (ai.topThemes && ai.topThemes.length > 0) {
  let themeText = '*Top Themes:*\n';
  ai.topThemes.forEach((t, i) => { themeText += (i + 1) + '. *' + t.theme + '* (' + t.threadCount + ' threads) - ' + t.description + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: themeText.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

(ai.threads || []).slice(0, 5).forEach(t => {
  let text = '*' + (t.title || 'Untitled') + '* (Score: ' + (t.relevanceScore || 'N/A') + ')\n';
  text += t.summary || '';
  if (t.url) text += '\n<' + t.url + '|View Thread>';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

if (ai.actionableInsights && ai.actionableInsights.length > 0) {
  blocks.push({ type: 'divider' });
  let insightText = '*Actionable Insights:*\n';
  ai.actionableInsights.forEach((ins, i) => { insightText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insightText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data saved to Google Sheets | Powered by Exa + Claude AI' }] });
const fallback = 'HN Trends: ' + (ai.trendingSummary || '').slice(0, 100);
return { blocks, fallback };
